class Solution {
public:
bool solve(vector<int>& nums, int k) {
    int n = nums.size();
    for (int i = 0; i < k; i++) {
        bool swapped = false;
        for (int j = 0; j < n - 1; j++) {
            if (nums[j] > nums[j + 1]) {
                swap(nums[j], nums[j + 1]);
                swapped = true;
            }
        }
        n = max(n - 1, 1);
        if (!swapped) {
            break;
        }
    }
    for (int i = 0; i < n - 1; i++) {
        if (nums[i] > nums[i + 1]) {
            return false;
        }
    }
    return true;
}
};
